// Prepare and optimize the prompt for ImageFX API
try {
  const promptText = $input.item.json.output;
  const briefData = $node['Parse and Structure Form Data2'].json;

  // Clean and optimize the prompt
  let optimizedPrompt = promptText
    .replace(/\n+/g, ' ')  // Remove newlines
    .replace(/\r/g, ' ')   // Remove carriage returns
    .replace(/\s+/g, ' ')  // Normalize whitespace
    .trim();

  // Ensure prompt isn't too long (ImageFX has limits)
  if (optimizedPrompt.length > 1000) {
    console.log('⚠️ Prompt too long, truncating to 1000 characters');
    optimizedPrompt = optimizedPrompt.substring(0, 997) + '...';
  }

  console.log('✅ Prompt prepared for ImageFX');
  console.log('📝 Prompt length:', optimizedPrompt.length);
  console.log('📝 First 100 chars:', optimizedPrompt.substring(0, 100));

  return {
    json: {
      authList: [
        {
          username: "gogohany56h@gmail.com",
          password: "YOUR_GOOGLE_APP_PASSWORD"  // App Password here
        }
      ],
      promptList: [
        {
          prompt: optimizedPrompt,
          size: "1:1",
          seed: -1
        }
      ],
      proxyConfiguration: {
        useApifyProxy: true,
        apifyProxyGroups: ["RESIDENTIAL", "GOOGLE_SERP"]
      },
      maxRequestRetries: 5,
      maxConcurrentRequests: 1,
      navigationTimeoutSecs: 180,
      pageLoadTimeoutSecs: 120,
      waitForSelectorTimeoutSecs: 60,
      metadata: {
        briefId: briefData.submissionId,
        brandName: briefData.sectionB.brandName,
        briefType: briefData.designCategory.isLogoDesign ? 'Logo Design' : 
                   briefData.designCategory.isSocialMedia ? 'Social Media' : 'General'
      }
    }
  };
} catch (error) {
  console.error('❌ Prompt preparation error:', error.message);
  throw new Error(`Failed to prepare prompt for ImageFX: ${error.message}`);
}

// Extract and process successful ImageFX response
try {
  const response = $input.item.json;
  const briefData = $node['Parse and Structure Form Data2'].json;
  const promptData = $node['AI: Generate Professional Design Prompt'].json;

  console.log('🔍 Processing ImageFX response...');
  console.log('Response type:', typeof response);
  console.log('Is array:', Array.isArray(response));

  // Handle array response
  const items = Array.isArray(response) ? response : [response];
  const firstItem = items[0];

  if (!firstItem) {
    throw new Error('Empty response from ImageFX');
  }

  console.log('First item keys:', Object.keys(firstItem));

  // Extract image URL (ImageFX returns different field names)
  let imageUrl = '';

  if (firstItem.imageUrl) {
    imageUrl = firstItem.imageUrl;
  } else if (firstItem.image) {
    imageUrl = firstItem.image;
  } else if (firstItem.url) {
    imageUrl = firstItem.url;
  } else if (firstItem.imageLink) {
    imageUrl = firstItem.imageLink;
  } else if (firstItem.link) {
    imageUrl = firstItem.link;
  }

  if (!imageUrl) {
    console.error('❌ No image URL found in response');
    console.error('Available fields:', Object.keys(firstItem));
    console.error('Full item:', JSON.stringify(firstItem, null, 2));
    throw new Error('No image URL found in ImageFX response');
  }

  console.log('✅ Image URL extracted:', imageUrl);

  return {
    json: {
      success: true,
      imageUrl: imageUrl,
      prompt: firstItem.prompt || promptData.output,
      metadata: {
        briefId: briefData.submissionId,
        briefType: briefData.designCategory.isLogoDesign ? 'Logo Design' : 
                   briefData.designCategory.isSocialMedia ? 'Social Media Design' : 'General Design',
        brandName: briefData.sectionB.brandName,
        submissionDate: briefData.submissionDate,
        imageSize: firstItem.size || '1:1',
        generationTime: new Date().toISOString()
      },
      fullResponse: firstItem
    }
  };
} catch (error) {
  console.error('❌ ImageFX response processing error:', error.message);
  throw error;
}

// Convert binary image to base64 for JSON response
try {
  const binaryData = $input.item.binary?.generatedImage;
  const jsonData = $input.item.json;

  if (!binaryData) {
    console.log('⚠️ No binary data, returning URL only');
    return {
      json: {
        success: true,
        message: 'Design brief processed and image generated successfully!',
        briefId: jsonData.metadata.briefId,
        briefType: jsonData.metadata.briefType,
        brandName: jsonData.metadata.brandName,
        submissionDate: jsonData.metadata.submissionDate,
        generatedPrompt: jsonData.prompt,
        imageGenerated: true,
        imageData: {
          imageUrl: jsonData.imageUrl,
          deliveryMethod: 'url',
          note: 'Image available via URL'
        }
      }
    };
  }

  // Get the buffer data
  const imageBuffer = binaryData.data;

  // Convert to base64
  const base64Image = imageBuffer.toString('base64');

  // Get mime type
  const mimeType = binaryData.mimeType || 'image/png';

  // Create data URL
  const imageDataUrl = `data:${mimeType};base64,${base64Image}`;

  console.log('✅ Image converted to base64');
  console.log('📊 Image size:', Math.round(imageBuffer.length / 1024), 'KB');

  return {
    json: {
      success: true,
      message: 'Design brief processed and image generated successfully! 🎨✨',
      briefId: jsonData.metadata.briefId,
      briefType: jsonData.metadata.briefType,
      brandName: jsonData.metadata.brandName,
      submissionDate: jsonData.metadata.submissionDate,
      generatedPrompt: jsonData.prompt,
      imageGenerated: true,
      imageData: {
        base64: base64Image,
        dataUrl: imageDataUrl,
        imageUrl: jsonData.imageUrl,
        mimeType: mimeType,
        sizeBytes: imageBuffer.length,
        sizeKB: Math.round(imageBuffer.length / 1024),
        deliveryMethod: 'base64+url'
      },
      generationMetadata: jsonData.metadata
    },
    binary: {
      generatedImage: binaryData
    }
  };
} catch (error) {
  console.error('❌ Image conversion error:', error.message);

  // Fallback to URL only
  const jsonData = $input.item.json;
  return {
    json: {
      success: true,
      message: 'Design brief processed successfully (image via URL)',
      briefId: jsonData.metadata?.briefId || 'N/A',
      briefType: jsonData.metadata?.briefType || 'N/A',
      brandName: jsonData.metadata?.brandName || 'N/A',
      imageGenerated: true,
      imageData: {
        imageUrl: jsonData.imageUrl,
        deliveryMethod: 'url',
        note: 'Base64 conversion failed, using URL',
        error: error.message
      }
    }
  };
}

// Handle ImageFX API failure with detailed analysis
try {
  const errorData = $input.item.json;
  const briefData = $node['Parse and Structure Form Data2']?.json;
  const promptData = $node['AI: Generate Professional Design Prompt']?.json;

  console.error('❌ ImageFX API Failed');
  console.error('Error data:', JSON.stringify(errorData, null, 2));

  let errorMessage = 'Image generation failed';
  let errorDetails = 'Unknown error occurred';
  let errorType = 'UNKNOWN';
  let solution = '';

  const errorString = JSON.stringify(errorData).toLowerCase();

  // Analyze error type
  if (errorString.includes('auth') || errorString.includes('401') || errorString.includes('403')) {
    errorType = 'AUTHENTICATION';
    errorMessage = 'Authentication failed';
    errorDetails = 'Google account credentials are invalid or expired';
    solution = '🔑 Solution: Update your Google App Password in the "Prepare ImageFX Input" node. Go to https://myaccount.google.com/apppasswords to create a new one.';
  } else if (errorString.includes('proxy') || errorString.includes('connection')) {
    errorType = 'PROXY';
    errorMessage = 'Proxy or connection error';
    errorDetails = 'Unable to connect to Google ImageFX through Apify proxy';
    solution = '🌐 Solution: Check your Apify account balance and proxy settings. You may need to add credits or try a different proxy group.';
  } else if (errorString.includes('timeout')) {
    errorType = 'TIMEOUT';
    errorMessage = 'Request timeout';
    errorDetails = 'Image generation took too long and exceeded the time limit';
    solution = '⏱️ Solution: Try again with a simpler prompt or increase the timeout value in the HTTP Request node.';
  } else if (errorString.includes('rate') || errorString.includes('limit') || errorString.includes('429')) {
    errorType = 'RATE_LIMIT';
    errorMessage = 'Rate limit exceeded';
    errorDetails = 'Too many requests to Google ImageFX API';
    solution = '🚦 Solution: Wait 15-30 minutes before trying again, or use a different Google account.';
  } else if (errorString.includes('token') || errorString.includes('apify')) {
    errorType = 'API_TOKEN';
    errorMessage = 'Invalid Apify API token';
    errorDetails = 'The Apify API token is missing or invalid';
    solution = '🔐 Solution: Get your API token from https://console.apify.com/account/integrations and update it in the "Generate Image via ImageFX" node.';
  } else if (errorString.includes('actor') || errorString.includes('build')) {
    errorType = 'ACTOR_ERROR';
    errorMessage = 'Apify Actor error';
    errorDetails = 'The ImageFX Actor failed to execute properly';
    solution = '🔧 Solution: The Actor may be temporarily unavailable. Try again in a few minutes or check Apify status.';
  } else if (errorData.error) {
    errorDetails = typeof errorData.error === 'string' ? errorData.error : JSON.stringify(errorData.error);
  }

  return {
    json: {
      success: false,
      message: errorMessage,
      errorType: errorType,
      errorDetails: errorDetails,
      solution: solution,
      briefId: briefData?.submissionId || 'N/A',
      brandName: briefData?.sectionB?.brandName || 'N/A',
      generatedPrompt: promptData?.output || null,
      imageGenerated: false,
      timestamp: new Date().toISOString(),
      suggestion: 'The design brief was processed successfully and a professional AI prompt was generated. However, image generation failed. You can use the generated prompt with other AI image services like Midjourney, DALL-E 3, or Stable Diffusion.',
      alternativeServices: [
        'Midjourney (https://midjourney.com)',
        'DALL-E 3 via ChatGPT Plus (https://chat.openai.com)',
        'Leonardo.ai (https://leonardo.ai)',
        'Ideogram (https://ideogram.ai)'
      ],
      debugInfo: {
        fullError: errorData,
        nodeExecutionTime: new Date().toISOString()
      }
    }
  };
} catch (error) {
  console.error('❌ Error handler itself failed:', error.message);
  return {
    json: {
      success: false,
      message: 'Critical error in error handling',
      error: error.message,
      timestamp: new Date().toISOString()
    }
  };
}

