try {
  // Try multiple ways to get the prompt text
  let promptText = null;

  // Method 1: Check if output exists in current item
  if ($input.item.json.output) {
    promptText = $input.item.json.output;
  }
  // Method 2: Check if text exists
  else if ($input.item.json.text) {
    promptText = $input.item.json.text;
  }
  // Method 3: Check previous node directly
  else if ($node && $node['AI: Generate Professional Design Prompt'] && $node['AI: Generate Professional Design Prompt'].json) {
    promptText = $node['AI: Generate Professional Design Prompt'].json.output || 
                 $node['AI: Generate Professional Design Prompt'].json.text;
  }
  // Method 4: Check if entire json is the prompt
  else if (typeof $input.item.json === 'string') {
    promptText = $input.item.json;
  }

  // Validate we have a prompt
  if (!promptText) {
    console.error('❌ No prompt found in input');
    console.error('Available keys:', Object.keys($input.item.json));
    console.error('Full input:', JSON.stringify($input.item.json, null, 2));
    throw new Error('No prompt text found. Please check the AI prompt generation node output.');
  }

  console.log('✅ Prompt text found:', promptText.substring(0, 100) + '...');

  // Convert to string if needed
  promptText = String(promptText);

  // Clean and optimize the prompt
  let optimizedPrompt = promptText
    .replace(/\n+/g, ' ')     // Remove newlines
    .replace(/\r/g, ' ')      // Remove carriage returns
    .replace(/\s+/g, ' ')     // Normalize whitespace
    .replace(/"/g, '')        // Remove quotes that might break JSON
    .trim();

